# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public float health = 100f;
    public int currency = 100;

    private void TakeDamage(float damage)
    {
        health -= damage;
        if (health <= 0)
        {
            HealthZero();
        }
    }

    private void HealthZero()
    {
        Debug.Log("Player health is zero!");
        // Handle player death
    }

    public bool PurchaseItem(int itemCost)
    {
        if (currency >= itemCost)
        {
            currency -= itemCost;
            return true;
        }
        else
        {
            return false;
        }
    }

    public float CalculateDamage(float baseDamage, float damageMultiplier)
    {
        return baseDamage * damageMultiplier;
    }
}